mapper.select:
select 
from score sc
left join exam e on sc.exam_id = e.id
left join paper p on sc.paper_id = p.id
left join candidate c on sc.candidate_id = c.id


        and sc.exam_id = #{examId}


        and sc.candidate_id = #{candidateId}


        and p.department_id = #{departmentId}


order by sc.total_score desc, sc.create_time desc

mapper.update:
update score
total_score = #{totalScore}, objective_score = #{objectiveScore}, subjective_score = #{subjectiveScore}, `rank` = #{rank},
where id = #{id}
